import{_ as a,o as i,c as e,a5 as t}from"./chunks/framework.B5tqjWbr.js";const c=JSON.parse('{"title":"概念：UPS C 参数表（UPS C parameter table）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：UPS C 参数表（UPS C parameter table）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0026-ups-c-parameter-table.html` 的源稿和补充资料。它只使用教学参数，不包含公司内部参数、未公开产品方案、客户项目参数或内部测试数据。向导师提问时不能记录公司内部参数，不能记录公司内部 NVM 格式，也不能记录客户项目参数。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-c-parameter-table.md","filePath":"content/power/concepts/embedded/ups-c-parameter-table.md","lastUpdated":null}'),l={name:"content/power/concepts/embedded/ups-c-parameter-table.md"};function p(n,s,h,r,k,d){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="概念-ups-c-参数表-ups-c-parameter-table" tabindex="-1">概念：UPS C 参数表（UPS C parameter table） <a class="header-anchor" href="#概念-ups-c-参数表-ups-c-parameter-table" aria-label="Permalink to &quot;概念：UPS C 参数表（UPS C parameter table）&quot;">​</a></h1><p>本页是 <code>lessons/0026-ups-c-parameter-table.html</code> 的源稿和补充资料。它只使用教学参数，不包含公司内部参数、未公开产品方案、客户项目参数或内部测试数据。向导师提问时不能记录公司内部参数，不能记录公司内部 NVM 格式，也不能记录客户项目参数。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>UPS C 参数表（UPS C parameter table）是把不间断电源（uninterruptible power supply / UPS）的保护阈值、同步保持时间、控制周期等工程参数集中放在一个结构体或配置模块里，而不是散落在状态机、保护函数和驱动代码中。</p><p>本节只讲一个概念：把教学阈值集中到 <code>UpsParameters</code>，让 C 工程更容易读、测、问。参数表不是控制算法本身，而是控制和保护逻辑共同引用的边界条件。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>UPS 软件里到处都有参数：市电欠压阈值、直流母线过压阈值、旁路同步保持时间、控制中断服务程序（control interrupt service routine / control ISR）周期等。如果这些数字直接写在代码逻辑里，读代码时很难判断某个数字是物理约束、保护阈值、调试临时值还是产品配置。</p><p>集中参数表能让你先建立阅读路径：先看参数名，再看谁使用它，最后看参数变化会影响哪些模式和保护。</p><p>从信号链路看，采样值先来自模数转换器（analog-to-digital converter / ADC），再和参数表里的阈值比较，最后变成保护标志或模式切换条件。没有参数表，采样、保护和状态机之间的边界会很难读。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>参数表像控制柜门板上的整定清单。状态机决定“当前走哪条路”，参数表决定“判断某条路是否安全时采用什么边界”。</p><p>例如欠压保护（undervoltage protection / UVP）不是凭感觉判断电压低，而是拿采样值和阈值比较。过压保护（overvoltage protection / OVP）也是同样思路。</p><p>如果将来参数需要掉电保存，常见入口会牵涉非易失性存储器（non-volatile memory / NVM）。本节先不实现保存，只建立“默认参数从哪里来、谁读取它”的阅读路径。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>典型判断可以写成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mains_uv_fault = (mains_rms_v &lt; mains_uv_threshold_v)</span></span>
<span class="line"><span>dc_bus_ov_fault = (dc_bus_v &gt; dc_bus_ov_threshold_v)</span></span>
<span class="line"><span>bypass_ready = sync_window_ok &amp;&amp; (sync_hold_ms &gt;= bypass_sync_hold_ms)</span></span></code></pre></div><p>教学代码中的参数表：</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typedef</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mains_uv_threshold_v;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> dc_bus_ov_threshold_v;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bypass_sync_hold_ms;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> control_isr_period_us;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} UpsParameters;</span></span></code></pre></div><p>这些数值只用于训练阅读结构，不代表真实 UPS 产品参数。</p><h2 id="_5-仿真任务与仿真观察" tabindex="-1">5. 仿真任务与仿真观察 <a class="header-anchor" href="#_5-仿真任务与仿真观察" aria-label="Permalink to &quot;5. 仿真任务与仿真观察&quot;">​</a></h2><p>本节的“仿真”仍然是可编译 C 教学程序。运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gcc </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">std</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c99 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Wall </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Wextra </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Werror </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">I projects\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">03</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ups</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firmware</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">skeleton\\src projects\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">03</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ups</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firmware</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">skeleton\\src\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.c </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o projects\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">03</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ups</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firmware</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">skeleton\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ups_c_firmware_skeleton.exe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">projects\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">03</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ups</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firmware</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">skeleton\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ups_c_firmware_skeleton.exe</span></span></code></pre></div><p>先观察第一行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>parameter_table: mains_uv=180.0V dc_bus_ov=420.0V bypass_hold=30ms isr=100us</span></span></code></pre></div><p>然后再看后续 tick 的模式变化。重点不是背这些数值，而是确认参数表在程序启动时可见、可追踪、可作为导师问题的具体产物。</p><p>不要背教学数值：<code>180.0V</code>、<code>420.0V</code>、<code>30ms</code> 和 <code>100us</code> 只是用于让输出可检查。真正要掌握的是 <code>parameters.h -&gt; UpsParameters</code> 定义边界，<code>parameters.c -&gt; UpsParameters_GetDefault()</code> 提供默认值。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><ul><li><code>parameters.h -&gt; UpsParameters</code>：定义参数结构体和参数访问接口。</li><li><code>parameters.c</code>：返回教学默认参数，并打印参数表摘要。</li><li><code>main.c</code>：启动时读取参数表并打印，形成可检查的运行证据。</li></ul><p>真实工程中参数可能来自 Flash、EEPROM、上位机配置、编译期常量或校准区。本课只做最小教学版本，不记录任何公司内部参数或内部 NVM 格式。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>错误理解：参数表只是为了少写几个数字。<br> 正确理解：参数表的核心价值是让阈值、时间和周期有名字、有边界、有审查入口。</li><li>错误理解：参数集中后就一定可以随便在线修改。<br> 正确理解：很多参数涉及安全，需要权限、范围检查、版本管理和掉电保存策略。</li><li>错误理解：导师给的真实参数可以直接记进学习仓库。<br> 正确理解：不能记录公司内部参数，只能记录通用组织方式、命名方式和审查思路。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>。</li><li>能指出 <code>UpsParameters</code> 里每个字段的工程含义。</li><li>能指出 <code>parameters.h -&gt; UpsParameters</code> 是结构边界，<code>parameters.c -&gt; UpsParameters_GetDefault()</code> 是默认值入口。</li><li>能解释为什么参数表比散落的魔法数字更适合阅读和审查。</li><li>能基于 <code>parameters.c -&gt; UpsParameters_GetDefault()</code> 准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>为什么 <code>mains_uv_threshold_v</code> 这种名字比代码里直接写 <code>180.0f</code> 更适合阅读？</li><li>为什么 <code>bypass_sync_hold_ms</code> 不应该只藏在旁路切换函数内部？</li><li>采样值先来自 ADC，再和参数表里的阈值比较；这句话对应代码里的哪些模块边界？</li><li>如果将来参数来自 Flash，<code>UpsParameters_GetDefault()</code> 这个接口还能保留什么价值？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>parameters.c -&gt; UpsParameters_GetDefault()</code> 看到教学参数集中在一个结构体。真实工程里保护阈值通常集中在参数表、保护模块，还是驱动配置里？</li><li>我用 <code>parameters.h -&gt; UpsParameters</code> 看到结构体字段带单位后缀。真实工程里参数命名通常如何标注单位、读写权限和范围？</li><li>我看到教学代码把旁路同步保持时间（bypass synchronization hold time）作为参数。真实工程里保持时间通常由哪个模块使用和审查？</li><li>我不会记录公司内部参数，只想确认组织方式：真实工程里参数是否有范围检查、默认值恢复和版本号？</li></ul>`,37)])])}const E=a(l,[["render",p]]);export{c as __pageData,E as default};
